supabase
      .channel('realtime-sender-notifications')
      .on('postgres_changes', {
        event: 'UPDATE',
        schema: 'public',
        table: 'orders',
        filter: `sender_id=eq.${uid}`,
      }, (payload: any) => {
        const n = payload.new;
        const o = payload.old;

        // Update the order in the table
        setOrders(prev => prev.map(ord => ord.id === n.id ? { ...ord, ...n } : ord));

        // Build activity event
        let message = `Order #${n.code} updated`;
        let type: ActivityEvent['type'] = 'update';
        if (o.status !== 'fulfilled' && n.status === 'fulfilled') {
          message = `${n.recipient_name} collected the gift at the shop.`;
          type = 'fulfilled';
          toast.success('Gift collected — escrow disbursed.');
        } else if (o.status !== 'paid' && n.status === 'paid') {
          message = `Payment confirmed. Funds locked in escrow for order #${n.code}.`;
          type = 'paid';
        }

        setFeed(prev => [{
          id: `${n.id}-${Date.now()}`,
          orderId: n.id,
          code: n.code,
          message,
          timestamp: new Date().toISOString(),
          type,
        }, ...prev].slice(0, 20));
      })
      .subscribe

supabase.channel('realtime-sender-notifications')
      .on('postgres_changes', {
        event: 'UPDATE',
        schema: 'public',
        table: 'orders',
        filter: `sender_id=eq.${user?.id || profile.id}`
      }, (payload: any) => {
        if (payload.new.status === 'fulfilled' && payload.old.status !== 'fulfilled') {
          toast.success(`🎉 Gift collected! Your recipient just picked up their item.`);
          setUnreadCount(prev => prev + 1);
          fetchNotifications(); // Refresh the list to get joined item/shop data
        }
      }).subscribe

